insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-1617', 'dumbbell decline one arm hammer press', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie on a decline bench with a dumbbell in one hand, resting on your chest.','Extend your arm straight up, keeping your elbow slightly bent.','Lower the dumbbell down towards your shoulder, keeping your elbow close to your body.','Press the dumbbell back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'SHUMp5H'),
  ('db-0305', 'dumbbell decline shrug', 'Back', 'Dumbbell', 'traps', ARRAY['shoulders','rhomboids']::text[], ARRAY['Set up a decline bench at a 45-degree angle.','Lie face down on the bench with your chest and stomach resting against it.','Hold a dumbbell in each hand with your arms fully extended towards the floor.','Keeping your arms straight, raise your shoulders towards your ears as high as possible.','Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cwsAI4G'),
  ('db-0304', 'dumbbell decline shrug v. 2', 'Back', 'Dumbbell', 'traps', ARRAY['shoulders','rhomboids']::text[], ARRAY['Set up a decline bench at a 45-degree angle.','Lie face down on the bench with your chest and stomach resting on it.','Hold a dumbbell in each hand with your palms facing each other and your arms fully extended.','Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together.','Hold the contraction for a brief pause, then lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bRlbdjK'),
  ('db-0306', 'dumbbell decline triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other.','Extend your arms fully, keeping your elbows close to your head.','Lower the dumbbells slowly behind your head, bending your elbows.','Pause for a moment, then raise the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OTgkHwR'),
  ('db-0307', 'dumbbell decline twist fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Lie down on a decline bench with your head lower than your hips.','Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest.','Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.','As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement.','Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top.','Repeat for the desired number of repetitions.']::text[], 'reFHapa'),
  ('db-1437', 'dumbbell finger curls', 'Arms', 'Dumbbell', 'forearms', ARRAY['wrist flexors','wrist extensors']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up.','Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers.','Repeat for the desired number of repetitions, then switch to the other hand.']::text[], 'mtXengz'),
  ('db-0308', 'dumbbell fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.','Extend your arms straight up over your chest, with a slight bend in your elbows.','Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yz9nUhF'),
  ('db-1277', 'dumbbell fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball and hold a dumbbell in each hand.','Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball.','Extend your arms straight up above your chest, palms facing each other.','Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Lt3iWnf'),
  ('db-1732', 'dumbbell forward lunge triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.','Take a step forward with your right foot, lowering your body into a lunge position.','Keep your back straight and your chest up.','Extend your arms straight overhead, keeping your elbows close to your ears.','Lower the dumbbells behind your head by bending your elbows.','Pause for a moment, then straighten your arms to return to the starting position.','Repeat the movement for the desired number of repetitions, then switch legs and repeat.']::text[], 'XalXcvM'),
  ('db-0310', 'dumbbell front raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['biceps','trapezius']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.','Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '3eGE2JC'),
  ('db-0309', 'dumbbell front raise v. 2', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.','Keep your back straight and engage your core.','Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Rr7S3yg'),
  ('db-0311', 'dumbbell full can lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rotator cuff']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.','Keep your back straight and engage your core.','Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'AQ0mC4Y'),
  ('db-1760', 'dumbbell goblet squat', 'Legs', 'Dumbbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.','Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yn8yg1r'),
  ('db-0313', 'dumbbell hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.','Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.','This will be your starting position.','Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Then, inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.']::text[], 'slDvUAU'),
  ('db-1659', 'dumbbell hammer curl on exercise ball', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'fY68AyX'),
  ('db-0312', 'dumbbell hammer curl v. 2', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.','Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.','This will be your starting position.','Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Then, inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.']::text[], '2NpxjC1'),
  ('db-2402', 'dumbbell hammer curls (with arm blaster)', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.','Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.','This will be your starting position.','Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Then, inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.']::text[], 'GNhAeJ0'),
  ('db-1664', 'dumbbell high curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with a dumbbell in each hand, palms facing forward.','Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qAmNMJY'),
  ('db-3545', 'dumbbell incline alternate press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, resting on your thighs.','Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward.','Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward.','Push the dumbbells up with your chest and shoulders, extending your arms fully.','Lower the dumbbells back down to the starting position, keeping your elbows slightly bent.','Repeat for the desired number of repetitions, alternating arms.']::text[], 'TVdivgY'),
  ('db-0314', 'dumbbell incline bench press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.','Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.','Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.','Push the dumbbells back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'ns0SIbU'),
  ('db-0315', 'dumbbell incline biceps curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'F3xgbjF'),
  ('db-0316', 'dumbbell incline breeding', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your back against the pad and feet flat on the ground.','Hold a dumbbell in each hand with an overhand grip, palms facing forward.','Start with your arms fully extended, perpendicular to the ground.','Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.','Pause for a moment at the bottom, then push the dumbbells back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'B3Rxp6L'),
  ('db-0318', 'dumbbell incline curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward.','Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ae9UoXQ'),
  ('db-0317', 'dumbbell incline curl v. 2', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RaflbWD'),
  ('db-0319', 'dumbbell incline fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Set an incline bench to a 45-degree angle.','Sit on the bench with a dumbbell in each hand, palms facing each other.','Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.','Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ESOd5Pl'),
  ('db-1278', 'dumbbell incline fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on an exercise ball and roll forward until your upper back is resting on the incline bench.','Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.','Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.','Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HYe1ZqR'),
  ('db-0320', 'dumbbell incline hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended.','Keep your back against the bench and your feet flat on the floor.','While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ByX0WxV'),
  ('db-0321', 'dumbbell incline hammer press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs.','Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other.','Press the dumbbells up and away from your body until your arms are fully extended.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PG1kcIb'),
  ('db-1618', 'dumbbell incline hammer press on exercise ball', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on an exercise ball with a dumbbell in each hand, palms facing each other.','Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball.','Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.','Press the dumbbells up and slightly inward, keeping your palms facing each other.','Extend your arms fully, squeezing your triceps at the top of the movement.','Slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wkgnGfb'),
  ('db-0322', 'dumbbell incline inner biceps curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing each other.','Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LCtQPn8'),
  ('db-1279', 'dumbbell incline one arm fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Adjust the incline bench to a 30-45 degree angle.','Sit on the bench with a dumbbell in one hand, resting it on your thigh.','Lie back on the bench, keeping your feet flat on the ground.','Hold the dumbbell with your arm extended straight up over your chest.','Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.','Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'Gw2HFvW'),
  ('db-1280', 'dumbbell incline one arm fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Sit on an exercise ball with a dumbbell in one hand.','Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.','Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards.','Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.','Pause for a moment when your arm is parallel to the ground.','Engage your chest muscles to bring the dumbbell back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'LLNh6q5'),
  ('db-1619', 'dumbbell incline one arm hammer press', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','chest']::text[], ARRAY['Sit on an incline bench with a dumbbell in one hand, resting on your thigh.','Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height.','Rotate your wrist so that your palm is facing inward, towards your body.','Press the dumbbell up and away from your body, extending your arm fully.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'LL1UiTX'),
  ('db-1620', 'dumbbell incline one arm hammer press on exercise ball', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','chest']::text[], ARRAY['Sit on an exercise ball with a dumbbell in one hand.','Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.','Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle.','Press the dumbbell up towards the ceiling, straightening your arm.','Lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'jDnrkar'),
  ('db-0323', 'dumbbell incline one arm lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','triceps']::text[], ARRAY['Sit on an incline bench with a dumbbell in one hand, resting it on your thigh.','Lean forward and position your upper arm against the inside of your thigh.','Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down.','Continue lifting until your arm is parallel to the floor.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'aTNKZiC'),
  ('db-1281', 'dumbbell incline one arm press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an incline bench with a dumbbell in one hand, resting on your thigh.','Lie back on the bench and position the dumbbell at shoulder level, palm facing forward.','Press the dumbbell upward and slightly inward, extending your arm fully.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'rDAiRf9'),
  ('db-1282', 'dumbbell incline one arm press on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground.','Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball.','Hold the dumbbell at shoulder height with your palm facing forward.','Press the dumbbell upward until your arm is fully extended.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'Bg5JKSH'),
  ('db-0324', 'dumbbell incline palm-in press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with a dumbbell in each hand, palms facing each other.','Plant your feet firmly on the ground and keep your back straight against the bench.','Start with the dumbbells at shoulder level, elbows bent and palms facing each other.','Press the dumbbells up and away from your body, extending your arms fully.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OVLmUuL'),
  ('db-1283', 'dumbbell incline press on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with a dumbbell in each hand, palms facing forward.','Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball.','Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.','Press the dumbbells upward, extending your arms fully.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bfiHMpI'),
  ('db-0325', 'dumbbell incline raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','triceps']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, resting on your thighs.','Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward.','Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'nxW6BkN'),
  ('db-0326', 'dumbbell incline rear lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Sit on the bench with your chest against the backrest and hold a dumbbell in each hand.','Extend your arms straight down with your palms facing each other.','Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vYk8lqw'),
  ('db-0327', 'dumbbell incline row', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Set up an incline bench at a 45-degree angle.','Grab a dumbbell in each hand and sit on the bench with your chest against the incline.','Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.','Pull the dumbbells up towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '7vG5o25'),
  ('db-0328', 'dumbbell incline shoulder raise', 'Chest', 'Dumbbell', 'serratus anterior', ARRAY['deltoids','trapezius']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down.','Rest the dumbbells on your thighs and lean back onto the bench.','Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward.','Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.','Repeat for the desired number of repetitions.']::text[], '6e2DcYX'),
  ('db-0329', 'dumbbell incline shrug', 'Back', 'Dumbbell', 'traps', ARRAY['shoulders']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand.','Place your feet flat on the ground and let your arms hang straight down with your palms facing your body.','Keeping your arms straight, shrug your shoulders up towards your ears as high as possible.','Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JymLInS'),
  ('db-3542', 'dumbbell incline t-raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.','Lean forward and let your arms hang straight down, perpendicular to the floor.','Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a ''T'' shape with your body.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jgbvVJ0'),
  ('db-0330', 'dumbbell incline triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing inwards.','Extend your arms fully overhead, keeping your elbows close to your head.','Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary.','Pause for a moment, then raise the dumbbells back to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'OVIKwsd'),
  ('db-0331', 'dumbbell incline twisted flyes', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other.','Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended.','Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.','As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement.','Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top.','Repeat for the desired number of repetitions.']::text[], '1PLE8e9'),
  ('db-1733', 'dumbbell incline two arm extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on an incline bench with a dumbbell in each hand, resting on your thighs.','Slowly lie back on the bench, keeping the dumbbells close to your chest.','Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'U7D9Fx3'),
  ('db-3541', 'dumbbell incline y-raise', 'Back', 'Dumbbell', 'upper back', ARRAY['shoulders','rear deltoids']::text[], ARRAY['Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.','Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows.','Raise your arms out to the sides and up in a Y shape until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PbzNu7c'),
  ('db-0332', 'dumbbell iron cross', 'Shoulders', 'Dumbbell', 'delts', ARRAY['triceps','chest']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.','Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body.','Pause for a moment, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cALkHHX'),
  ('db-0333', 'dumbbell kickback', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.','Extend your arms straight back, squeezing your triceps at the top of the movement.','Pause for a moment, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'W6PxUkg'),
  ('db-1734', 'dumbbell kickbacks on exercise ball', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','back']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle.','Extend your arms straight back, squeezing your triceps at the top of the movement.','Pause for a moment, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cAvTaSg'),
  ('db-1660', 'dumbbell kneeling bicep curl exercise ball', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Kneel on the floor with an exercise ball in front of you.','Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up.','Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], '2JCuFTU'),
  ('db-0334', 'dumbbell lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.','Keep your back straight and engage your core.','Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'DsgkuIt'),
  ('db-0335', 'dumbbell lateral to front raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.','Keep your back straight and engage your core.','Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xMjBKwn'),
  ('db-0336', 'dumbbell lunge', 'Legs', 'Dumbbell', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.','Take a step forward with your right foot, lowering your body into a lunge position.','Keep your back straight and your chest up as you lower your body.','Push through your right heel to return to the starting position.','Repeat with your left leg.','Alternate legs for the desired number of repetitions.']::text[], 'RRWFUcw'),
  ('db-1658', 'dumbbell lunge with bicep curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['quadriceps','hamstrings']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.','Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.','As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body.','Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides.','Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot.','Continue alternating sides for the desired number of repetitions.']::text[], 'Mz6lLcW'),
  ('db-0337', 'dumbbell lying extension (across face)', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.','Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other.','Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground.','Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'L2V5Nan'),
  ('db-1729', 'dumbbell lying alternate extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.','Extend your arms straight up over your chest, keeping a slight bend in your elbows.','Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended.','Pause for a moment at the bottom, then raise the dumbbell back up to the starting position.','Repeat with the other arm, alternating sides for the desired number of repetitions.']::text[], 'NfP83rA'),
  ('db-0338', 'dumbbell lying elbow press', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest.','Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary.','Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows.','Repeat for the desired number of repetitions.']::text[], 'eOCOwIR'),
  ('db-0863', 'dumbbell lying external shoulder rotation', 'Shoulders', 'Dumbbell', 'delts', ARRAY['rotator cuff','triceps']::text[], ARRAY['Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees.','Hold a dumbbell in your hand with your palm facing down.','Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible.','Pause for a moment at the top, then slowly lower your forearm back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'bmBf7LN'),
  ('db-0339', 'dumbbell lying femoral', 'Legs', 'Dumbbell', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen.','Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'FkBIE6a'),
  ('db-0340', 'dumbbell lying hammer press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.','Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.','Press the dumbbells back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '7gdLIXa'),
  ('db-2470', 'dumbbell lying on floor rear delt raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Lie face down on the floor with a dumbbell in each hand, palms facing each other.','Extend your arms straight out in front of you, keeping a slight bend in your elbows.','Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Ion0XWz'),
  ('db-0341', 'dumbbell lying one arm deltoid rear', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards.','Extend your arm straight down towards the floor, keeping it close to your body.','Raise your arm up and back, squeezing your shoulder blade towards your spine.','Pause for a moment at the top, then slowly lower your arm back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'gSw59a4'),
  ('db-0343', 'dumbbell lying one arm press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground.','Hold the dumbbell at shoulder level with your palm facing forward.','Press the dumbbell upward until your arm is fully extended.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'zGSIWQi'),
  ('db-0342', 'dumbbell lying one arm press v. 2', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with your back supported and feet flat on the ground.','Hold a dumbbell in one hand with your palm facing towards your feet.','Extend your arm straight up towards the ceiling, keeping your elbow slightly bent.','Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body.','Pause for a moment at the bottom, then push the dumbbell back up to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'K3dIO25'),
  ('db-0344', 'dumbbell lying one arm pronated triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with your back and head supported, and your feet flat on the ground.','Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder.','Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.','Pause for a moment at the bottom, then extend your arm back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'wyaqzOS'),
  ('db-0345', 'dumbbell lying one arm rear lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor.','Keep your arm straight and lift the dumbbell out to the side, away from your body.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'KwFGiEP'),
  ('db-0346', 'dumbbell lying one arm supinated triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['forearms']::text[], ARRAY['Lie flat on a bench with your back and head supported, and your feet flat on the ground.','Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder.','Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.','Pause for a moment at the bottom, then extend your arm back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'zZlORz6'),
  ('db-0347', 'dumbbell lying pronation', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand.','Rotate your palms so they are facing up.','Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down.','Inhale and slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mym4hJo'),
  ('db-2705', 'dumbbell lying pronation on floor', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand.','Rotate your palms so they are facing down towards the floor.','Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms.','Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level.','Hold for a moment, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '7RWNjiB'),
  ('db-1284', 'dumbbell lying pullover on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders','back']::text[], ARRAY['Sit on an exercise ball and roll forward until your upper back is resting on the ball.','Hold a dumbbell with both hands and extend your arms straight up over your chest.','Slowly lower the dumbbell behind your head while keeping your arms straight.','Pause for a moment, then raise the dumbbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'iK59oEA'),
  ('db-1328', 'dumbbell lying rear delt row', 'Back', 'Dumbbell', 'upper back', ARRAY['shoulders','biceps']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards.','Extend your arms straight down towards the floor, keeping a slight bend in your elbows.','Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XUUD0Fs'),
  ('db-0348', 'dumbbell lying rear lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.','Extend your arms straight down towards the floor, keeping a slight bend in your elbows.','Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '53Ttlck'),
  ('db-1735', 'dumbbell lying single extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.','Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.','Pause briefly at the bottom of the movement, then extend your arm back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], '6MfS53i'),
  ('db-0349', 'dumbbell lying supination', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground.','Hold a dumbbell in each hand with your palms facing up and your arms fully extended.','Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms.','Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'M2Pm3zj'),
  ('db-2706', 'dumbbell lying supination on floor', 'Arms', 'Dumbbell', 'forearms', ARRAY['biceps','shoulders']::text[], ARRAY['Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand.','Rotate your palms to face up, keeping your elbows close to your sides.','Slowly curl the dumbbells towards your shoulders, squeezing your forearms.','Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rEhi2o5'),
  ('db-1661', 'dumbbell lying supine biceps curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie flat on a bench with your back and head supported, and your feet flat on the ground.','Hold a dumbbell in each hand with your palms facing up and your arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XVzF3iZ'),
  ('db-0350', 'dumbbell lying supine curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KUaZst7'),
  ('db-0351', 'dumbbell lying triceps extension', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.','Extend your arms straight up over your chest, keeping your elbows close to your body.','Lower the dumbbells down towards your forehead, bending your elbows.','Pause for a moment, then extend your arms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mpKZGWz'),
  ('db-1662', 'dumbbell lying wide curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qm9veZw'),
  ('db-0352', 'dumbbell neutral grip bench press', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest.','Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body.','Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'pP8wP2P'),
  ('db-1285', 'dumbbell one arm bench fly', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders']::text[], ARRAY['Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh.','Lie back on the bench, keeping the dumbbell pressed against your thigh.','Using your free hand, help lift the dumbbell up to the starting position.','Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward.','Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.','Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms and repeat.']::text[], 'o5Jsk92'),
  ('db-0292', 'dumbbell one arm bent-over row', 'Back', 'Dumbbell', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.','Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.','Let the dumbbell hang straight down towards the floor, with your arm fully extended.','Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'C0MA9bC'),
  ('db-1286', 'dumbbell one arm chest fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.','Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball.','Extend your arm with the dumbbell straight up above your chest, palm facing inward.','Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.','Pause for a moment when your arm is parallel to the ground.','Engage your chest muscles to bring the dumbbell back up to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'Bpkf41o'),
  ('db-0353', 'dumbbell one arm concentration curl (on stability ball)', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor.','Rest your elbow on the inside of your thigh, just above the knee.','Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps.','Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms and repeat.']::text[], 'k5IpyHg'),
  ('db-1287', 'dumbbell one arm decline chest press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie on a decline bench with a dumbbell in one hand, resting on your chest.','Place your feet flat on the ground and keep your back pressed against the bench.','Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'REGM1dE'),
  ('db-1288', 'dumbbell one arm fly on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.','Walk your feet forward and roll your body down until your upper back is resting on the exercise ball.','Extend your arm with the dumbbell straight up above your chest, palm facing inwards.','Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.','Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'Am02iPd'),
  ('db-1736', 'dumbbell one arm french press on exercise ball', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle.','Extend your arm straight up towards the ceiling, keeping your elbow stationary.','Slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'ziFKQXP'),
  ('db-1663', 'dumbbell one arm hammer preacher curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.','Hold the dumbbell with a neutral grip (palms facing your body).','Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], '4dF3maG'),
  ('db-1621', 'dumbbell one arm hammer press on exercise ball', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders','chest']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your back straight.','Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle.','Place your other hand on your hip for stability.','Press the dumbbell upwards, extending your arm fully.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'VYmYxK5'),
  ('db-1289', 'dumbbell one arm incline chest press', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the incline bench to a 45-degree angle.','Sit on the bench with your back against the pad and feet flat on the ground.','Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder.','Push the dumbbell up and away from your body, extending your arm fully.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'PDaMuyV'),
  ('db-0354', 'dumbbell one arm kickback', 'Arms', 'Dumbbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Bring your right elbow up to your side, keeping it bent at a 90-degree angle.','Extend your right arm straight back, squeezing your triceps at the top of the movement.','Slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'bQy2Eni'),
  ('db-0355', 'dumbbell one arm lateral raise', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.','Keep your back straight and your core engaged throughout the exercise.','Raise the dumbbell to the side, keeping your arm straight and your palm facing down.','Continue lifting until your arm is parallel to the ground.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'n5cWCsI'),
  ('db-0356', 'dumbbell one arm lateral raise with support', 'Shoulders', 'Dumbbell', 'delts', ARRAY['trapezius','rotator cuff']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body.','Place your other hand on a stable surface, such as a bench or wall, for support.','Keep your back straight and engage your core.','Raise the dumbbell out to the side, keeping your arm straight and your palm facing down.','Continue lifting until your arm is parallel to the ground.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'Yg7MJAT'),
  ('db-1290', 'dumbbell one arm press on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['shoulders','triceps','core']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward.','Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'QZFv5ui'),
  ('db-1665', 'dumbbell one arm prone curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in one hand, palm facing down.','Extend your arm fully, letting it hang straight down towards the floor.','Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps.','Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'JWjujiY'),
  ('db-1666', 'dumbbell one arm prone hammer curl', 'Arms', 'Dumbbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended.','Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps.','Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'LIGZSTA'),
  ('db-1291', 'dumbbell one arm pullover on exercise ball', 'Chest', 'Dumbbell', 'pectorals', ARRAY['triceps','latissimus dorsi','rhomboids']::text[], ARRAY['Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold a dumbbell with one hand and extend your arm straight up above your chest.','Slowly lower the dumbbell behind your head while keeping your arm straight.','Pause for a moment, then raise the dumbbell back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'bQHPBU3')
